CREATE TABLE IF NOT EXISTS `studio_bookings` (`id` int AUTO_INCREMENT NOT NULL, `contactId` int, `leadId` int, `assignedUserId` int, `title` varchar(255) NOT NULL, `sessionType` enum('recording','mixing','mastering','rehearsal','other') DEFAULT 'recording', `status` enum('scheduled','confirmed','in_progress','completed','cancelled') DEFAULT 'scheduled', `startAt` timestamp NOT NULL, `endAt` timestamp NOT NULL, `studio` varchar(128) DEFAULT 'Estudio Principal', `engineer` varchar(255), `notes` text, `value` decimal(12,2), `invoiceId` int, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `studio_bookings_id` PRIMARY KEY(`id`));

CREATE TABLE IF NOT EXISTS `tasks` (`id` int AUTO_INCREMENT NOT NULL, `title` varchar(255) NOT NULL, `description` text, `assignedUserId` int, `contactId` int, `leadId` int, `priority` enum('low','medium','high','urgent') DEFAULT 'medium', `status` enum('pending','in_progress','done','cancelled') DEFAULT 'pending', `dueDate` timestamp, `completedAt` timestamp, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `tasks_id` PRIMARY KEY(`id`));

CREATE TABLE IF NOT EXISTS `whatsapp_chats` (`id` int AUTO_INCREMENT NOT NULL, `jid` varchar(128) NOT NULL, `name` varchar(255), `isGroup` boolean DEFAULT false, `contactId` int, `lastMessageAt` timestamp, `lastMessagePreview` text, `unreadCount` int DEFAULT 0, `syncedAt` timestamp, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `whatsapp_chats_id` PRIMARY KEY(`id`), CONSTRAINT `whatsapp_chats_jid_unique` UNIQUE(`jid`));

CREATE TABLE IF NOT EXISTS `whatsapp_messages` (`id` int AUTO_INCREMENT NOT NULL, `messageId` varchar(255) NOT NULL, `chatJid` varchar(128) NOT NULL, `chatId` int, `senderJid` varchar(128), `senderName` varchar(255), `crmUserId` int, `crmUserName` varchar(255), `content` text, `mediaType` enum('text','image','video','audio','document','sticker') DEFAULT 'text', `mediaUrl` text, `isFromMe` boolean DEFAULT false, `timestamp` bigint, `createdAt` timestamp NOT NULL DEFAULT (now()), CONSTRAINT `whatsapp_messages_id` PRIMARY KEY(`id`), CONSTRAINT `whatsapp_messages_messageId_unique` UNIQUE(`messageId`));

